    "plantGrade": "dicot",
    "name": {
      "nl": "Dagkoekoeksbloem",
      "en": "Red Campion",
      "fr": "Silène dioïque"
    },
    "habitat": {
      "nl": "Vochtige bosranden, heggen, houtwallen en schaduwrijke plaatsen op voedselrijke bodems.",
      "en": "Moist woodland edges, hedges, hedgerows and shaded places on nutrient-rich soils.",
      "fr": "Lisières forestières humides, haies et endroits ombragés sur sols riches."
    },
    "rarity": {
      "nl": "Algemeen in heel België.",
      "en": "Common throughout Belgium.",
      "fr": "Commun dans toute la Belgique."
    },
    "description": {
      "nl": "Tweeslachtige vaste plant 30–90 cm met felroze-rode bloemen. Mannelijke en vrouwelijke planten apart. Bloeit april–november (soms al februari). Bloemdeksels van vrouwelijke plant kelkachtig opgezwollen. Hybridiseert met witte koekoeksbloem (S. latifolia). Populaire insectenplant.",
      "en": "Dioecious perennial 30–90 cm with bright pink-red flowers. Male and female plants separate. Flowers April–November (sometimes February). Calyx of female plant bladder-like inflated. Hybridises with white campion (S. latifolia). Popular insect plant.",
      "fr": "Vivace dioïque 30–90 cm aux fleurs rose-rouge vif. Plantes mâles et femelles séparées. Floraison avril–novembre (parfois février). Calice de la plante femelle vésiculeux gonflé. Hybride avec la silène blanche (S. latifolia). Plante populaire pour les insectes."
    },
    "size": {
      "nl": "30–90 cm hoog",
      "en": "30–90 cm tall",
      "fr": "30–90 cm de hauteur"
    },
    "diet": {
      "nl": "Fotosynthese.",
      "en": "Photosynthesis.",
      "fr": "Photosynthèse."
    },
